async function waitForIncrementalIndexEvent(getMessagesSince: (since: number) => Promise<MatrixEvent[]>, since: number) {
    try {
        await waitUntil(async () => {
            let matrixMessages = await getMessagesSince(since);
            return matrixMessages.some((m) => m.type === APP_BOXEL_REALM_EVENT_TYPE &&
                m.content.eventName === 'index' &&
                m.content.indexType === 'incremental');
        });
    }
    catch (e) {
        let matrixMessages = await getMessagesSince(since);
        console.log('waitForIncrementalIndexEvent failed, no event found. Events:');
        console.log(JSON.stringify(matrixMessages, null, 2));
        throw e;
    }
}
function findRealmEvent(events: MatrixEvent[], eventName: string, indexType: string): RealmEvent | undefined {
    return events.find((m) => m.type === APP_BOXEL_REALM_EVENT_TYPE &&
        m.content.eventName === eventName &&
        (realmEventIsIndex(m.content) ? m.content.indexType === indexType : true)) as RealmEvent | undefined;
}
function realmEventIsIndex(event: RealmEventContent): event is IncrementalIndexEventContent {
    return event.eventName === 'index';
}
